scwin.f_Retrieve = function() {
    console.log("============f_Retrieve===========");
    if (!$c.gus.cfIsAfterDate( ica_stDt.getValue(), ica_endDt.getValue() )){
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); 
        ica_stDt.focus();
        return;
    }

    //거래내역 초기 세팅
    // tac_tabControl1.setSelectedTabIndex(0);

    // if ($c.gus.cfValidate([ica_stDt]) == true && $c.gus.cfValidate([ica_stDt]) == true)
    // {
        scwin.insertFlag = "0";
        // ds_condition.UseChangeInfo = false;
        // tr_retrieve.post();
        $c.sbm.execute(sbm_retrieve);
    // }
};

